def is_samepatterns(patterns):
    """
    Check whether the strings in patterns array follow a consistent pattern.

    Args:
        patterns: List of strings

    Returns:
        bool: True if the strings follow the same pattern, False otherwise
    """
    if not patterns:
        return True

    # Create a mapping from pattern indices to string indices
    mapping = {}
    # Track used pattern indices
    used_pattern = {}

    for i, word in enumerate(patterns):
        if word not in used_pattern:
            if word in mapping:
                return False
            mapping[word] = i
            used_pattern[i] = word

    # Check if all words map to the same pattern structure
    for i, word in enumerate(patterns):
        # If the word appears multiple times, all occurrences should be the same
        if patterns.count(word) > 1:
            # All occurrences should have the same pattern
            for j, w in enumerate(patterns):
                if w == word and j != i:
                    if mapping.get(w) != mapping.get(word):
                        return False

    return True

