def sequence(n):
    if n == 1:
        return 1

    # Create a list to store the sequence values
    # We need to track up to index n (0-indexed means n+1 elements)
    seq = [0] * (n + 1)
    seq[1] = 1

    for i in range(2, n + 1):
        seq[i] = seq[i - 1] if seq[i - 1] != 1 else seq[i - 2]

    return seq[n]

