        return 0

    sequence_list = [0] * (n + 1)
    sequence_list[1] = 1

    for i in range(2, n + 1):
        sequence_list[i] = sequence_list[sequence_list[i - 1]] + sequence_list[i - sequence_list[i - 1]]

