        divisors = set()
        for i in range(1, int(num**0.5) + 1):
            if num % i == 0:
                divisors.add(i)
                divisors.add(num // i)
        return divisors

    def is_amicable(a, b):
        if a == b:
            return False
        divs_a = get_divisors(a)
        divs_b = get_divisors(b)
        return sum(divs_a) == b and sum(divs_b) == a

    amicable_pairs = set()
    for i in range(1, n + 1):
        if i in amicable_pairs:
            continue
        divs_i = get_divisors(i)
        sum_divs = sum(divs_i)
        if sum_divs != i and sum_divs <= n:
            if is_amicable(i, sum_divs):
                amicable_pairs.add(i)
                amicable_pairs.add(sum_divs)

    return sum(amicable_pairs)

