    Sum all amicable numbers from 1 to a specified number.

    Two numbers are amicable if the sum of proper divisors of each equals the other.
    """
    def sum_of_proper_divisors(n):
        """Calculate the sum of proper divisors of n."""
        if n <= 1:
            return 0
        total = 1  # 1 is always a proper divisor for n > 1
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                total += i
                if i != n // i:
                    total += n // i
        return total

    def is_amicable(n, limit):
        """Check if n is an amicable number."""
        if n > limit:
            return False
        other = sum_of_proper_divisors(n)
        if other == n:
            return False  # Perfect number, not amicable
        if other > limit:
            return False
        return sum_of_proper_divisors(other) == n

    sum_total = 0
    for n in range(1, limit + 1):
        if is_amicable(n, limit):
            sum_total += n

    return sum_total

