def magic_square_test(matrix):
    n = len(matrix)

    # Check if matrix is square
    if len(matrix[0]) != n:
        return False

    # Check if all elements are positive integers
    for row in matrix:
        for element in row:
            if not isinstance(element, int) or element <= 0:
                return False

    # Calculate the magic constant
    magic_constant = n * (n * n + 1) // 2

    # Check if all rows sum to the magic constant
    for row in matrix:
        if sum(row) != magic_constant:
            return False

    # Check if all columns sum to the magic constant
    for col in range(n):
        col_sum = sum(matrix[row][col] for row in range(n))
        if col_sum != magic_constant:
            return False

    # Check if the main diagonal sums to the magic constant
    main_diagonal_sum = sum(matrix[i][i] for i in range(n))
    if main_diagonal_sum != magic_constant:
        return False

    # Check if the anti-diagonal sums to the magic constant
    anti_diagonal_sum = sum(matrix[i][n - 1 - i] for i in range(n))
    if anti_diagonal_sum != magic_constant:
        return False

    return True

