def zero_count(arr):
    """
    Returns the ratio of zeroes to non-zeroes in an array of integers.
    """
    zeroes = sum(1 for x in arr if x == 0)
    non_zeroes = sum(1 for x in arr if x != 0)
    if non_zeroes == 0:
        return float('nan')
    return zeroes / non_zeroes

