def is_majority(arr, n, element):
    if n == 0:
        return False

    # Since the array is sorted, we can use binary search to find the first and last occurrences
    def binary_search_first(arr, n, element):
        left, right = 0, n - 1
        result = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                result = mid
                right = mid - 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return result

    def binary_search_last(arr, n, element):
        left, right = 0, n - 1
        result = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == element:
                result = mid
                left = mid + 1
            elif arr[mid] < element:
                left = mid + 1
            else:
                right = mid - 1
        return result

    first_index = binary_search_first(arr, n, element)
    if first_index == -1:
        return False

    last_index = binary_search_last(arr, n, element)
    count = last_index - first_index + 1

    return count > n // 2

