def bell_number(n):
    if n == 0:
        return 1

    # Build Bell triangle (Aitken's array)
    triangle = []
    for i in range(n + 1):
        row = []
        if i == 0:
            row = [1]
        else:
            # Start with the last element of the previous row
            row.append(triangle[i-1][-1])
            # Fill the rest of the row
            for j in range(1, i):
                row.append(triangle[i-1][j-1] + row[j-1])
        triangle.append(row)

    return triangle[n][-1]

def is_Monotonic(arr):
    # Handle edge cases
    if len(arr) <= 1:
        return True

    # Check if non-decreasing
    non_decreasing = True
    for i in range(1, len(arr)):
        if arr[i] < arr[i-1]:
            non_decreasing = False
            break

    # Check if non-increasing
    non_increasing = True
    for i in range(1, len(arr)):
        if arr[i] > arr[i-1]:
            non_increasing = False
            break

    return non_decreasing or non_increasing

def is_Monotonic(arr):
