def is_samepatterns(patterns, argpatterns):
    # Create a mapping from each unique string in patterns to a unique character
    mapping = {}
    char_counter = 1

    # Check if the pattern structure matches the given sequence
    for i, pattern in enumerate(patterns):
        if pattern in mapping:
            if mapping[pattern] != argpatterns[i]:
                return False
        else:
            # Assign a new character to this pattern
            mapping[pattern] = argpatterns[i]
            char_counter += 1

    # Ensure all unique patterns are mapped to unique characters
    # Check if the mapping is consistent
    for pattern in patterns:
        if pattern in mapping:
            if mapping[pattern] != argpatterns[patterns.index(pattern)]:
                return False

    return True

