def sequence(n):
    """
    Calculate the nth number in the Newman-Conway sequence.

    The Newman-Conway sequence is defined as:
    - a(1) = 1
    - a(n) = a(a(n-1)) for n > 1

    Args:
        n: A positive integer representing the position in the sequence

    Returns:
        The nth number in the Newman-Conway sequence
    """
    if n <= 0:
        raise ValueError("n must be a positive integer")

    memo = {}

    def helper(k):
        if k in memo:
            return memo[k]
        if k == 1:
            memo[k] = 1
        else:
            memo[k] = helper(helper(k - 1))
        return memo[k]

    return helper(n)

